 document.querySelectorAll('[data-te]').forEach(x=>x.onclick=async()=>{const t=treatmentOptions.find(y=>y.id===x.dataset.te),name=prompt('處理方式名稱',t.name);if(name?.trim()){const z=await sb.from('treatment_options').update({name:name.trim()}).eq('id',t.id);if(z.error)return alert(z.error.message);await audit('修改處理方式','treatment_option',t.id,name.trim())}$('#modal').close();await load();treatmentManager()});
 document.querySelectorAll('[data-tt]').forEach(x=>x.onclick=async()=>{const id=x.dataset.tt,t=treatmentOptions.find(y=>y.id===id),z=await sb.from('treatment_options').update({is_active:!t.is_active}).eq('id',id);if(z.error)return alert(z.error.message);await audit(t.is_active?'停用處理方式':'重新啟用處理方式','treatment_option',id,t.name);$('#modal').close();await load();treatmentManager()});
 document.querySelectorAll('[data-tx]').forEach(x=>x.onclick=async()=>{const t=treatmentOptions.find(y=>y.id===x.dataset.tx);if(t.usage_count){if(confirm(`此處理方式已被使用於 ${t.usage_count} 筆病歷，無法永久刪除。是否改為停用？`)){await sb.from('treatment_options').update({is_active:false}).eq('id',t.id);await audit('停用處理方式','treatment_option',t.id,t.name)}return}if(confirm('確定要永久刪除此處理方式嗎？此操作無法復原。')){await sb.from('treatment_options').delete().eq('id',t.id);await audit('刪除處理方式','treatment_option',t.id,t.name);$('#modal').close();await load();treatmentManager()}});
 document.querySelectorAll('[data-tu],[data-td]').forEach(x=>x.onclick=async()=>{await reorder('treatment_options',treatmentOptions,x.dataset.tu||x.dataset.td,x.dataset.tu?-1:1);$('#modal').close();treatmentManager()});
