 const batch=async action=>{const list=selected();if(!list.length)return alert('請先勾選處理方式');let deleted=0,disabled=0,changed=0;for(const t of list){if(action==='delete'){if(t.usage_count){await sb.from('treatment_options').update({is_active:false}).eq('id',t.id);disabled++}else{await sb.from('treatment_options').delete().eq('id',t.id);deleted++}}else{await sb.from('treatment_options').update(action==='disable'?{is_active:false}:{is_active:true}).eq('id',t.id);changed++}}await audit('批次管理處理方式','treatment_option',null,`刪除 ${deleted}、停用 ${disabled}、變更 ${changed}`);alert(`完成：永久刪除 ${deleted} 項、改為停用 ${disabled} 項、其他變更 ${changed} 項`);$('#modal').close();await load();treatmentManager()};
