async function adminCall(body){const{data,error}=await sb.functions.invoke('admin-users',{body});if(error)return{error:{message:error.context?await error.context.text():error.message}};if(data?.error)return{error:{message:data.error}};return{data}}
$('#users').onclick=accountManager;
async function accountManager(){const result=await adminCall({action:'list'});if(result.error)return alert(result.error.message);const data=result.data?.users||[];form('帳號與權限管理',`<button type="button" class="primary" id="addSubAdmin">＋ 新增子管理員</button><div class="managerList">${data.map(u=>`<div class="manageCard"><span><b>${esc(u.display_name||u.email)}</b><small>${esc(u.email)} · ${u.role==='super_admin'?'主管理員':'子管理員'} · ${u.active?'啟用':'停用'}<br>建立：${new Date(u.created_at).toLocaleString('zh-TW',{hour12:false})} · 最後登入：${u.last_login_at?new Date(u.last_login_at).toLocaleString('zh-TW',{hour12:false}):'尚未登入'}</small></span><span>${u.role==='super_admin'?'<b>主管理員</b>':`<button type="button" data-uedit="${u.id}">編輯／權限</button><button type="button" data-upass="${u.id}">重設密碼</button><button type="button" data-ulog="${u.id}">操作紀錄</button><button type="button" data-udel="${u.id}">刪除</button>`}</span></div>`).join('')}</div>`,()=>({}),'關閉');$('#addSubAdmin').onclick=addSubAdmin;document.querySelectorAll('[data-uedit]').forEach(x=>x.onclick=()=>editSubAdmin(data.find(u=>u.id===x.dataset.uedit)));document.querySelectorAll('[data-upass]').forEach(x=>x.onclick=()=>resetSubPassword(data.find(u=>u.id===x.dataset.upass)));document.querySelectorAll('[data-ulog]').forEach(x=>x.onclick=()=>showUserLogs(data.find(u=>u.id===x.dataset.ulog)));document.querySelectorAll('[data-udel]').forEach(x=>x.onclick=async()=>{if(!confirm('確定要永久刪除此從未使用的帳號嗎？'))return;const z=await adminCall({action:'delete',user_id:x.dataset.udel});if(z.error)return alert(z.error.message);$('#modal').close();accountManager()})}
function addSubAdmin(){form('新增子管理員',`<label class="field">顯示名稱<input name="display_name" required></label><label class="field">登入帳號<input name="email" type="email" required></label><label class="field">初始密碼<input name="password" type="password" minlength="8" required></label><label class="field">確認密碼<input name="confirm" type="password" minlength="8" required></label><label><input type="checkbox" name="active" checked> 帳號啟用</label><label><input type="checkbox" name="must_change_password" checked> 下次登入必須修改密碼</label>${permissionFields()}`,f=>{if(f.get('password')!==f.get('confirm'))return{error:{message:'兩次密碼不一致'}};return adminCall({action:'create',display_name:f.get('display_name'),email:f.get('email'),password:f.get('password'),active:f.get('active')==='on',must_change_password:f.get('must_change_password')==='on',permissions:getPermissions(f)})},'建立子管理員')}
function editSubAdmin(u){form('編輯子管理員',`<label class="field">顯示名稱<input name="display_name" value="${esc(u.display_name||'')}" required></label><label><input type="checkbox" name="active" ${u.active?'checked':''}> 帳號啟用</label>${permissionFields(u.permissions||{})}`,f=>adminCall({action:'update',user_id:u.id,display_name:f.get('display_name'),active:f.get('active')==='on',permissions:getPermissions(f)}),'儲存變更')}
function resetSubPassword(u){form('重設子管理員密碼',`<p>${esc(u.email)}</p><label class="field">新密碼<input name="password" type="password" minlength="8" required></label><label class="field">確認密碼<input name="confirm" type="password" minlength="8" required></label><label><input type="checkbox" name="must_change_password" checked> 下次登入必須修改密碼</label>`,f=>f.get('password')!==f.get('confirm')?{error:{message:'兩次密碼不一致'}}:adminCall({action:'reset_password',user_id:u.id,password:f.get('password'),must_change_password:f.get('must_change_password')==='on'}),'重設密碼')}
async function showUserLogs(u){const{data}=await sb.from('audit_logs').select('*').eq('user_id',u.id).order('created_at',{ascending:false}).limit(100);form(`${u.display_name||u.email}－操作紀錄`,(data||[]).map(x=>`<div class="manageCard"><span><b>${esc(x.action)}</b><small>${new Date(x.created_at).toLocaleString('zh-TW',{hour12:false})} · ${esc(x.entity_type||'系統')} ${esc(x.entity_id||'')}<br>${esc(x.description||'')}</small></span></div>`).join('')||'<p>尚無操作紀錄</p>',()=>({}),'關閉')}
$('#importJson').onclick=()=>$('#jsonFile').click();$('#jsonFile').onchange=async e=>{const file=e.target.files[0];if(!file)return;let doc;try{doc=JSON.parse(await file.text())}catch{return alert('JSON 檔案格式錯誤')}if(doc.schema_version!==2||!Array.isArray(doc.categories)||!Array.isArray(doc.patients)||!Array.isArray(doc.records))return alert('這不是 AT Case Library v2 完整備份');if(!confirm(`即將匯入：${doc.categories.length} 個分類、${doc.patients.length} 位個案、${doc.records.length} 筆紀錄。\n目前資料會先自動備份，再由匯入資料取代。確定繼續？`))return;const x=await sb.rpc('import_case_library_json',{p_payload:doc});if(x.error)return alert(x.error.message);alert('JSON 匯入完成');location.reload()};
$('#backup').onclick=async()=>{const{data:backs}=profile.role==='super_admin'?await sb.from('backup_snapshots').select('id,reason,created_at').order('created_at',{ascending:false}):{data:[]};form('資料備份與移轉',`<div class="recordActions">${profile.role==='super_admin'?'<button type="button" id="jsonImport">匯入 JSON</button>':''}<button type="button" id="jsonOut">匯出 JSON</button><button type="button" id="csvOut">匯出 CSV</button><button type="button" id="xlsOut">匯出 Excel</button><button type="button" id="sqlOut">SQL 封存</button></div>${profile.role==='super_admin'?`<button type="button" id="backupNow">立即建立雲端備份</button><h3>最近備份</h3>${(backs||[]).slice(0,50).map(b=>`<div class="userrow"><span>${new Date(b.created_at).toLocaleString('zh-TW')}<small>${esc(b.reason)}</small></span><button type="button" data-restore="${b.id}">還原</button></div>`).join('')}`:''}`,()=>({}),'關閉');const rows=patients.flatMap(p=>(p.records||[]).map(r=>({name:p.name,category:categories.find(c=>c.id===p.category_id)?.name,date:r.visit_date,body:r.body_part,treatment:r.treatment,notes:r.notes}))),doc={schema_version:2,exported_at:new Date().toISOString(),categories,patients:patients.map(({records,...p})=>p),records:patients.flatMap(p=>p.records||[])};if($('#jsonImport'))$('#jsonImport').onclick=()=>$('#jsonFile').click();$('#jsonOut').onclick=()=>download(`at-case-${Date.now()}.json`,JSON.stringify(doc,null,2),'application/json');$('#csvOut').onclick=()=>download(`at-case-${Date.now()}.csv`,['姓名,分類,日期,部位,處理方式,備註',...rows.map(r=>[r.name,r.category,r.date,r.body,r.treatment,r.notes].map(csv).join(','))].join('\n'),'text/csv;charset=utf-8');$('#xlsOut').onclick=()=>download(`at-case-${Date.now()}.xls`,`<table><tr><th>姓名</th><th>分類</th><th>日期</th><th>部位</th><th>處理方式</th><th>備註</th></tr>${rows.map(r=>`<tr>${Object.values(r).map(v=>`<td>${esc(v)}</td>`).join('')}</tr>`).join('')}</table>`,'application/vnd.ms-excel');$('#sqlOut').onclick=()=>download(`at-case-${Date.now()}.sql`,`-- AT Case Library offline archive\n-- JSON payload follows\n${JSON.stringify(doc)}`);if($('#backupNow'))$('#backupNow').onclick=async()=>{await sb.rpc('create_case_library_backup',{p_reason:'manual'});alert('備份完成')};document.querySelectorAll('[data-restore]').forEach(b=>b.onclick=async()=>{if(confirm('還原會覆蓋目前資料；系統會先備份當下狀態。確定繼續？')){const x=await sb.rpc('restore_case_library_backup',{p_backup_id:Number(b.dataset.restore)});if(x.error)return alert(x.error.message);location.reload()}})};
$('#homeBrand').onclick=attemptHome;$('#headerSettings').onclick=()=>navigate('settings');$('#continueEditing').onclick=()=>$('#homeConfirm').close();$('#discardHome').onclick=returnHomeNow;$('#globalSearch').oninput=()=>{if(currentView!=='search')navigate('search');else renderFolders({search:true})};$('#sort').onchange=applyRoute;document.querySelectorAll('[data-nav]').forEach(b=>b.onclick=()=>b.dataset.nav==='home'?attemptHome():navigate(b.dataset.nav));window.addEventListener('hashchange',applyRoute);
$('#modal').addEventListener('input',()=>{if($('#modal').open&&!$('#modal').classList.contains('statsModal'))modalDirty=true});$('#modal').addEventListener('change',()=>{if($('#modal').open&&!$('#modal').classList.contains('statsModal'))modalDirty=true});$('#modal').addEventListener('click',e=>{if(!$('#modal').open)return;const target=e.target.closest('button');if(target&&target.matches('[data-side],[data-body],#addBodyChoice,[data-body-treatment],[data-rmb],[data-quick-treatment]'))modalDirty=true});
let isSidebarOpen=false,touchStartX=0,touchStartY=0;
const isMobileSidebar=()=>window.matchMedia('(max-width:768px), (min-width:769px) and (max-width:1024px) and (orientation:portrait)').matches;
function setSidebarOpen(open,{returnFocus=true}={}){if(!isMobileSidebar()){isSidebarOpen=false;$('#sidebar').classList.remove('open');$('#sidebarOverlay').hidden=true;document.body.classList.remove('sidebarOpen');$('#mobileMenu').setAttribute('aria-expanded','false');return}isSidebarOpen=Boolean(open);$('#sidebar').classList.toggle('open',isSidebarOpen);$('#sidebarOverlay').hidden=!isSidebarOpen;document.body.classList.toggle('sidebarOpen',isSidebarOpen);$('#mobileMenu').setAttribute('aria-expanded',String(isSidebarOpen));$('#mobileMenu').setAttribute('aria-label',isSidebarOpen?'關閉主選單':'開啟主選單');if(isSidebarOpen)$('#sidebarClose').focus();else if(returnFocus)$('#mobileMenu').focus()}
$('#mobileMenu').onclick=()=>setSidebarOpen(!isSidebarOpen);$('#sidebarClose').onclick=()=>setSidebarOpen(false);$('#sidebarOverlay').onclick=e=>{e.preventDefault();e.stopPropagation();setSidebarOpen(false)};
document.addEventListener('click',e=>{if(!isSidebarOpen||!isMobileSidebar())return;const item=e.target.closest('#sidebar button');if(item&&item.id!=='sidebarClose')setSidebarOpen(false);if(e.target.closest('header nav button'))setSidebarOpen(false)});
document.addEventListener('keydown',e=>{if(e.key==='Escape'&&isSidebarOpen){e.preventDefault();setSidebarOpen(false)}});
$('#sidebar').addEventListener('touchstart',e=>{if(e.touches.length!==1)return;touchStartX=e.touches[0].clientX;touchStartY=e.touches[0].clientY},{passive:true});
$('#sidebar').addEventListener('touchend',e=>{if(!isSidebarOpen||!e.changedTouches.length)return;const dx=e.changedTouches[0].clientX-touchStartX,dy=e.changedTouches[0].clientY-touchStartY;if(dx<-60&&Math.abs(dx)>Math.abs(dy)*1.3)setSidebarOpen(false)},{passive:true});
window.addEventListener('resize',()=>{if(!isMobileSidebar()&&isSidebarOpen)setSidebarOpen(false,{returnFocus:false})});boot();
